solution:
use std::rc::Rc;

fn main() {
    let sun = Rc::new("Sun".to_string());

    println!("Reference count after creating sun: {}", Rc::strong_count(&sun));

    {
        let _planet1 = Rc::clone(&sun);
        println!("Reference count after creating planet1: {}", Rc::strong_count(&sun));

        let _planet2 = Rc::clone(&sun);
        println!("Reference count after creating planet2: {}", Rc::strong_count(&sun));
    }

    println!("Reference count after inner scope: {}", Rc::strong_count(&sun));
    assert_eq!(Rc::strong_count(&sun), 1);
}
